type TransformerConstructor func(schemaMapping.SchemaMapper) transform.Transformer

type messageProcessor struct {
	saramaConsumer    streaming.Consumer
	saramaProducer    streaming.Producer[*streaming.EventReturn]
	dlqProducer       streaming.Producer[*streaming.EventDiscard]
	fanOutProducer    streaming.Producer[*streaming.EventReturn]
	queryGenerator    queryGenerator.QueryGenerator
	grouper           group2.Grouper
	enricher          enrich.Enricher
	emitter           emitter.Emitter
	consolidator      *consolidate.Consolidator
	transformers      map[string][]transform.Transformer
	schemaMapper      schemaMapping.SchemaMapper
	queue             queue2.Queue[*transform.MessageModel]
	filter            filter.MessageFilter
	transformerCtor   TransformerConstructor
	auditLogBatchSize int
}

const BatchDocsThreshold string = "DOCS_PER_BATCH_THRESHOLD"

// MessageProcessorDependencies Message processor dependencies.
type MessageProcessorDependencies struct {
	Consumer                  streaming.Consumer
	Producer                  streaming.Producer[*streaming.EventReturn]
	DlqProducer               streaming.Producer[*streaming.EventDiscard]
	FanOutProducer            streaming.Producer[*streaming.EventReturn]
	QueryGenerator            queryGenerator.QueryGenerator
	Grouper                   group2.Grouper
	Enricher                  enrich.Enricher
	Emitter                   emitter.Emitter
	RemediationRequestEmitter emitter.RemediationRequestEmitter
	SchemaMapper              schemaMapping.SchemaMapper
	Filter                    filter.MessageFilter
	TransformerCtor           TransformerConstructor
}

// NewMessageProcessor returns an implementation of Processor.
//
// Undetermined behavior occurs if the dependencies or the log context pointers are nil.
func NewMessageProcessor(
	logContext *log.Context,
	dependencies *MessageProcessorDependencies,
	auditLogBatchSize int,
) Processor {
	if logContext == nil {
		panic("A nil log context was provided to NewMessageProcessor()")
	}

	if dependencies == nil {
		panic("A nil dependency pointer was provided to NewMessageProcessor()")
	}

	return &messageProcessor{
		saramaConsumer:  dependencies.Consumer,
		saramaProducer:  dependencies.Producer,
		dlqProducer:     dependencies.DlqProducer,
		fanOutProducer:  dependencies.FanOutProducer,
		transformerCtor: dependencies.TransformerCtor,
		queryGenerator:  dependencies.QueryGenerator,
		grouper:         dependencies.Grouper,
		enricher:        dependencies.Enricher,
		emitter:         dependencies.Emitter,
		schemaMapper:    dependencies.SchemaMapper,
		consolidator: &consolidate.Consolidator{
			SchemaMapping: dependencies.SchemaMapper,
		},
		transformers:      allocateTransformers(logContext, dependencies.Consumer),
		filter:            dependencies.Filter,
		auditLogBatchSize: auditLogBatchSize,
	}
}

// Producer returns current instance of the streaming.Producer interface.
func (mp *messageProcessor) Producer() streaming.Producer[*streaming.EventReturn] {
	return mp.saramaProducer
}

func (mp *messageProcessor) SetQueue(queue queue2.Queue[*transform.MessageModel]) {
	mp.queue = queue
}

func (mp *messageProcessor) SetProducer(producer streaming.Producer[*streaming.EventReturn]) {
	mp.saramaProducer = producer
}

func (mp *messageProcessor) SetDLQProducer(producer streaming.Producer[*streaming.EventDiscard]) {
	mp.dlqProducer = producer
}

// DLQProducer returns current instance of the streaming.Producer interface.
func (mp *messageProcessor) DLQProducer() streaming.Producer[*streaming.EventDiscard] {
	return mp.dlqProducer
}

func (mp *messageProcessor) SetFanOutProducer(producer streaming.Producer[*streaming.EventReturn]) {
	mp.fanOutProducer = producer
}

// NewMessageCallback handles transform and queue of messages.
func (mp *messageProcessor) NewMessageCallback(
	logContext *log.Context,
	tpo *streaming.TopicPartitionOffset,
	key []byte,
	message []byte,
	headers streaming.MessageHeaders,
) {
	const (
		createdTransformerMessage = "message_processor.NewMessageCallback: Created transformer for Topic: %s Partition: %d at Offset: %d"
		messageReceived           = "message_processor.NewMessageCallback: Received message to transform. Topic: %s Partition: %d at Offset: %d"
		skipMessage               = "message_processor.NewMessageCallback: Skipping message because transform returned no changes"
		errorConsumingMessage     = "message_processor.NewMessageCallback: Error occurred while consuming message."
		messageKey                = "message_key"
	)

	var (
		topic     = tpo.Topic()
		partition = tpo.Partition()
		offset    = tpo.Offset()
		eventName = headers.PayloadSchemaName()
		tags      = []metrics.Tag{
			metrics.NewTag(telemetry.PayloadSchemaNameTag, eventName),
			metrics.NewTag(telemetry.PayloadSchemaVersionTag, headers.PublicSchemaVersion()),
			metrics.NewTag(telemetry.EventTypeTag, headers.EventType()),
		}
		errorCode errorHandling.ErrorCode
	)

	log.Debugw(
		logContext,
		fmt.Sprintf(
			messageReceived,
			topic,
			partition,
			offset,
		),
		messageKey,
		string(key),
		log.PayloadSchemaNameKey,
		eventName,
	)

	dlqEvent := &streaming.EventDiscard{
		UemDlqEventProtocol: &uemPublicSchema.UemDlqEventProtocol{
			ErrorCode:      0,
			Offset:         offset,
			PartitionIndex: int64(partition),
			Payload:        message,
		},
		MessageHeaders: headers,
	}

	defer func() {
		if r := recover(); r != nil {
			if err, ok := r.(error); ok {
				errorCode = errorHandling.GetErrorCode[any](err)
				tags = append(
					tags,
					metrics.NewTag(telemetry.FailureTypeTag, errorCode.String()),
				)
			}

			dlqEvent.UemDlqEventProtocol.ErrorCode = errorCodes.MessageProcessorFailedToTransform.Code()
			dlqEvent.UemDlqEventProtocol.FailureMessage = fmt.Sprintf("%+v", r)
			mp.dlqProducer.Produce([]*streaming.EventDiscard{dlqEvent})

			mp.EmitProcessedMessageTelemetry(logContext, nil, metric.FailedMessageCount, tags...)

			log.Errorw(logContext, errorConsumingMessage, log.ErrorKey, r, log.MessageHeaderKey, headers)

			mp.PostOffsetMessage(logContext, tpo, headers)
		}
	}()

	transformer := mp.transformers[topic][partition]

	if transformer == nil {
		transformer = mp.transformerCtor(mp.schemaMapper)
		mp.transformers[topic][partition] = transformer
		log.Debugw(
			logContext,
			fmt.Sprintf(
				createdTransformerMessage,
				topic,
				partition,
				offset,
			),
			messageKey,
			string(key),
		)
	}

	if mp.filter.ShouldSkip(logContext, tpo, message, headers) {
		mp.EmitProcessedMessageTelemetry(logContext, nil, metric.ExcludedMessageCount, tags...)
		mp.PostOffsetMessage(logContext, tpo, headers)

		return
	}

	item, err := telemetry.MeasureWithResultAndError(
		logContext,
		group.Transformer,
		metric.Transform,
		func() (*transform.MessageModel, error) {
			return transformer.Transform(tpo, message, headers)
		},
		tags...,
	)
	if err != nil {
		panic(err)
	}

	if item == nil {
		log.Warnw(logContext, skipMessage, dlqEvent.LoggingFields()...)

		dlqEvent.UemDlqEventProtocol.ErrorCode = errorCodes.MessageProcessorMessageIgnored.Code()
		dlqEvent.UemDlqEventProtocol.FailureMessage = skipMessage
		mp.dlqProducer.Produce([]*streaming.EventDiscard{dlqEvent})
		mp.EmitProcessedMessageTelemetry(logContext, nil, metric.ExcludedMessageCount, tags...)
		mp.PostOffsetMessage(logContext, tpo, headers)

		return
	}

	item.Key = key
	item.DeadLetterMessage = dlqEvent
	mp.queue.Enqueue(item)
}

func (mp *messageProcessor) CommitMessages(logContext *log.Context, messages []*transform.MessageModel) {
	// We don't need to keep the latest offset because sarama already keeps track of this.
	//
	// We also don't have to worry about commit round-trips to Kafka since sarama keeps the offsets
	// in memory and sends the consolidated offsets to Kafka on a separate go routine at intervals
	// in the order of seconds.
	//
	// CommitOffset() uses internally the sarama MarkOffset function. Here is the relevant code:
	//
	// https://github.com/IBM/sarama/blob/main/consumer_group.go#L877
	// https://github.com/IBM/sarama/blob/main/offset_manager.go#L447
	// https://github.com/IBM/sarama/blob/main/offset_manager.go#L557
	//
	// There is a write lock in that code, but GI will suffer no contention because we always commit
	// from a single go routine, the auto-flush go routine.
	for _, message := range messages {
		mp.saramaConsumer.CommitOffset(logContext, message.OriginalMessage.TopicPartitionOffset)
	}
}

func (mp *messageProcessor) PostOffsetMessage(
	logContext *log.Context,
	tpo *streaming.TopicPartitionOffset,
	headers streaming.MessageHeaders,
) {
	// We enqueue offset messages so that we don't accumulate lag due to errors or
	// skipped messages.
	//
	// These offset messages carry no information but the offset and are ignored
	// during the batch consolidation process.
	offsetMessage := &transform.MessageModel{
		LogContext: logContext,
		OriginalMessage: &streaming.EventReturn{
			TopicPartitionOffset: tpo,
			MessageHeaders:       headers,
		},
	}
	mp.queue.Enqueue(offsetMessage)
}

func (mp *messageProcessor) ProcessMessageBatch(
	logContext *log.Context,
	messages []*transform.MessageModel,
) {
	const batchProcessingErrorMessage = "Error occurred while processing batch. Retrying individual messages."
	defer func() {
		if r := recover(); r != nil {
			log.Warnw(logContext, batchProcessingErrorMessage, log.ErrorKey, r)

			// Retry each message individually after a batch failure to identify
			// the actual failed message. Then, send only this message to the
			// Dead Letter Queue (DLQ) and record it as a failure.
			telemetry.IncrementFailure(
				logContext,
				group.MessageProcessor,
				metric.ProcessMessageBatch,
			)

			for _, message := range messages {
				mp.processFailedMessage(message)
			}
		}
	}()

	mp.processMessageBatchInternal(logContext, messages)
}

func (mp *messageProcessor) ProcessRemediationMessageBatch(*log.Context, []*transform.MessageModel) {
	panic("not implemented")
}

func (mp *messageProcessor) processFailedMessage(
	message *transform.MessageModel,
) {
	const messageProcessingErrorMessage = "Error occurred while retrying failed message. Sending message to DLQ."
	logContext := log.NewLogContextWithCorrelationIds(message.CorrelationId())
	defer func() {
		var (
			errorCode    errorHandling.ErrorCode
			dlqErrorCode int64 = 0
		)

		if r := recover(); r != nil {
			// record failed message metric and send the failed message to DLQ.
			tags := []metrics.Tag{
				metrics.NewTag(telemetry.PayloadSchemaNameTag, message.OriginalMessage.PayloadSchemaName()),
				metrics.NewTag(
					telemetry.PayloadSchemaVersionTag,
					message.OriginalMessage.MessageHeaders.PublicSchemaVersion(),
				),
				metrics.NewTag(telemetry.EventTypeTag, message.OriginalMessage.MessageHeaders.EventType()),
			}

			if err, ok := r.(error); ok {
				errorCode = errorHandling.GetErrorCode[any](err)
				dlqErrorCode = errorCode.Code()
				tags = append(
					tags,
					metrics.NewTag(telemetry.FailureTypeTag, errorCode.String()),
				)
			}

			mp.EmitProcessedMessageTelemetry(logContext, message, metric.FailedMessageCount, tags...)

			dlqEvent := &streaming.EventDiscard{
				UemDlqEventProtocol: &uemPublicSchema.UemDlqEventProtocol{
					ErrorCode:      dlqErrorCode,
					Offset:         message.OriginalMessage.Offset(),
					PartitionIndex: message.OriginalMessage.Partition(),
					Payload:        message.OriginalMessage.Payload,
					FailureMessage: fmt.Sprintf("%+v", r),
				},
				MessageHeaders: message.OriginalMessage.Headers(),
			}

			mp.dlqProducer.Produce([]*streaming.EventDiscard{dlqEvent})

			log.Errorw(
				logContext,
				messageProcessingErrorMessage,
				log.ErrorKey,
				r,
				log.IndexNameList,
				lo.Keys(message.Changes),
			)

			log.Debugw(
				logContext,
				messageProcessingErrorMessage,
				log.ErrorKey,
				r,
				log.ChangesKey,
				message.Changes.GetIndexChangesValueForLogging(mp.schemaMapper),
			)
		}
	}()

	mp.processMessageBatchInternal(logContext, []*transform.MessageModel{message})
}

func (mp *messageProcessor) processMessageBatchInternal(
	logContext *log.Context,
	messages []*transform.MessageModel,
) {
	const (
		FailedToGenerateQueriesErrorMessage     = "Failing batch because there was an error when generating queries"
		FailedToEmitQueriesErrorMessage         = "Failing batch because there was an error when emitting queries"
		FailedToEmitFanOutMessagesErrorMessage  = "Failing batch because there was an error when emitting fan out messages"
		FailedToEmitDriftedMessagesErrorMessage = "Failing batch because there was an error when emitting drifted messages"
	)

	// failBatchOnError fails the current batch if there was an error.
	//
	// The panic event triggers a one at a time message retry operation that
	// when it fails, puts the failing message in the DLQ.
	failBatchOnError := func(err error, queryModel *repository.QueryModel) {
		if err == nil {
			return
		}

		queryModel = nil

		// Panic to re-try the messages one by one and send the failures to DLQ.
		panic(err)
	}

	// Merging can only happen at the boundary of indices.
	//
	// The following code consolidate the messages by index.
	//
	// The consolidator also filters offset messages.
	indexDocumentChangeModelsMap := mp.consolidator.ConsolidateMessages(logContext, messages)
	if len(indexDocumentChangeModelsMap) == 0 {
		// Nothing to do.
		mp.EmitProcessedMessagesTelemetry(logContext, messages, metric.SuccessMessageCount)
		return
	}

	mp.logMessages(logContext, indexDocumentChangeModelsMap)

	telemetry.MeasureWithResult(
		logContext,
		group.Grouper,
		metric.Group,
		func() map[string][]*transform.IndexDocumentChangeModel {
			return mp.grouper.Group(logContext, indexDocumentChangeModelsMap)
		},
	)

	// Enrich events
	enricherError := telemetry.MeasureWithError(
		logContext,
		group.Enricher,
		metric.Enrich,
		func() error {
			return mp.enricher.Enrich(logContext, indexDocumentChangeModelsMap)
		},
	)

	// Until we capture more runtime data, we will only emit a warning for enrichment errors.
	//
	// Enrichment is considered an optional operation.
	_ = errorHandling.HandleWarning(logContext, enricherError)

	// populate queries
	queries := &repository.QueryModel{}
	queryGeneratorError := telemetry.MeasureWithError(
		logContext,
		group.QueryGenerator,
		metric.Generate,
		func() error {
			return mp.queryGenerator.Generate(logContext, indexDocumentChangeModelsMap, queries)
		},
	)

	failBatchOnError(
		errorHandling.Wrap(
			logContext,
			queryGeneratorError,
			errorCodes.MessageProcessorFailedToGenerateQueries,
			FailedToGenerateQueriesErrorMessage,
		),
		nil,
	)

	emitterError := telemetry.MeasureWithError(
		logContext, group.Emitter, metric.Emit, func() error {
			return mp.emitter.Emit(logContext, queries)
		},
	)
	failBatchOnError(
		errors.Wrap(
			emitterError,
			FailedToEmitQueriesErrorMessage,
		),
		queries,
	)

	fanOutError := telemetry.MeasureWithError(
		logContext,
		group.Publisher,
		metric.PublishMessages,
		func() error {
			return mp.emitFanOutMessages(
				logContext,
				queries,
			)
		},
		metrics.NewTag(telemetry.QueryTypeTag, pkg.FanOutMessagePushOperationId),
	)
	failBatchOnError(
		errorHandling.Wrap(
			logContext,
			fanOutError,
			errorCodes.MessageProcessorFailedToEmitFanOutMessages,
			FailedToEmitFanOutMessagesErrorMessage,
		),
		queries,
	)

	if ff.EnableDriftDetection.IsEnabled() {
		driftedError := telemetry.MeasureWithError(
			logContext,
			group.Publisher,
			metric.PublishMessages,
			func() error {
				return mp.emitDriftedEvents(
					logContext,
					indexDocumentChangeModelsMap,
				)
			},
			metrics.NewTag(telemetry.QueryTypeTag, pkg.DriftedMessagePushOperationId),
		)
		failBatchOnError(
			errorHandling.Wrap(
				logContext,
				driftedError,
				errorCodes.MessageProcessorFailedToEmitDriftedMessages,
				FailedToEmitDriftedMessagesErrorMessage,
			),
			queries,
		)
	}

	mp.EmitProcessedMessagesTelemetry(logContext, messages, metric.SuccessMessageCount)
}

func (mp *messageProcessor) EmitProcessedMessagesTelemetry(
	logContext *log.Context,
	messages []*transform.MessageModel,
	metricName string,
) {
	for _, message := range messages {
		tags := []metrics.Tag{
			metrics.NewTag(telemetry.PayloadSchemaNameTag, message.OriginalMessage.PayloadSchemaName()),
			metrics.NewTag(telemetry.EventTypeTag, message.OriginalMessage.MessageHeaders.EventType()),
		}

		mp.EmitProcessedMessageTelemetry(logContext, message, metricName, tags...)
	}
}

func (mp *messageProcessor) EmitProcessedMessageTelemetry(
	logContext *log.Context,
	message *transform.MessageModel,
	metricName string,
	tags ...metrics.Tag,
) {
	const (
		UnableToParseEventProtocolTimeStamp = "Unable to parse event protocol timestamp"
		UnableToParseMessageTimeStamp       = "Unable to parse message timestamp"
	)

	telemetry.Increment(
		logContext,
		group.MessageProcessor,
		metricName,
		tags...,
	)

	// in case of unknown events, UemEventProtocol will be nil
	if message != nil && message.OriginalMessage != nil && message.OriginalMessage.UemEventProtocol != nil {
		timestamp, err := iso8601.ParseString(message.OriginalMessage.UemEventProtocol.Timestamp)
		if errorHandling.HandleWarning(logContext, errors.Wrap(err, UnableToParseEventProtocolTimeStamp)) == nil {
			telemetry.Timing(
				logContext,
				group.MessageProcessor,
				metric.ProcessLatencyFromOrigin,
				time.Since(timestamp),
				tags...,
			)
		}

		timestamp, err = time.Parse(time.RFC3339, message.OriginalMessage.MessageHeaders.MessageTimeStamp())
		if errorHandling.HandleWarning(logContext, errors.Wrap(err, UnableToParseMessageTimeStamp)) == nil {
			telemetry.Timing(
				logContext,
				group.MessageProcessor,
				metric.ProcessLatencyFromSource,
				time.Since(timestamp),
				tags...,
			)
		}
	}
}

func allocateTransformers(
	logContext *log.Context,
	consumer streaming.Consumer,
) map[string][]transform.Transformer {
	const errorFmt = "an error occurred in 'message_processor.allocateTransformers' unable to retrieve partition information of topic '%s'"

	topics := consumer.Topics()
	transformers := make(map[string][]transform.Transformer, len(topics))
	for _, topic := range topics {
		partitions, err := consumer.Partitions(topic)
		errorHandling.HandleFatal(
			logContext,
			errors.Wrapf(err, errorFmt, topic),
		)
		transformers[topic] = make([]transform.Transformer, len(partitions))
	}

	return transformers
}

func (mp *messageProcessor) logMessages(
	logContext *log.Context,
	changes map[string][]*transform.IndexDocumentChangeModel,
) {
	if !logContext.IsVerboseEnabled() {
		return
	}

	defer errorHandling.Recover(logContext, nil)

	const (
		// if we log the entire batch then the log will cross the configured log size limit.
		processMessageBatchLogMessage = "message_processor.logMessages: Messages to process (chunk: %s)"
	)
	chunkUuid := uuid.NewString()

	for indexKey, allDocuments := range changes {
		for _, documents := range lo.Chunk(allDocuments, mp.auditLogBatchSize) {
			log.Verbosew(
				logContext,
				fmt.Sprintf(processMessageBatchLogMessage, chunkUuid),
				log.IndexName,
				indexKey,
				log.ChangesKey,
				// This is currently for quick troubleshooting in our build
				// pipelines, this FF is not meant for prod as we cannot log
				// potential PII. CRSVC-39454 will ensure this FF can't be
				// turned on in non dev environment.
				documents,
			)
		}
	}
}

func (mp *messageProcessor) emitFanOutMessages(
	logContext *log.Context,
	queryModel *repository.QueryModel,
) error {
	if len(queryModel.FanOutMessages) <= 0 {
		// Nothing to do.
		return nil
	}

	mp.fanOutProducer.Produce(queryModel.FanOutMessages.ToSlice())

	telemetry.Count(
		logContext,
		group.Publisher,
		metric.FanOutMessageCount,
		int64(len(queryModel.FanOutMessages)),
		metrics.NewTag(telemetry.OperationIdTag, pkg.FanOutMessagePushOperationId),
	)

	return nil
}

func (mp *messageProcessor) emitDriftedEvents(
	logContext *log.Context,
	indexDocumentChangeModelsMap map[string][]*transform.IndexDocumentChangeModel,
) error {
	const driftedMessage = "Drifted"

	var dlqEvents []*streaming.EventDiscard

	for _, indexChanges := range indexDocumentChangeModelsMap {
		for _, indexChange := range indexChanges {
			if indexChange.Merged || indexChange.IsPartialDocument {
				continue
			}

			for _, driftState := range indexChange.SequenceNumberIdToDriftStateMap {
				if driftState.SequenceState.IsOK() {
					continue
				}

				event := driftState.MessageModel.OriginalMessage

				dlqEvents = append(
					dlqEvents, &streaming.EventDiscard{
						UemDlqEventProtocol: &uemPublicSchema.UemDlqEventProtocol{
							ErrorCode:      errorCodes.MessageProcessorMessageDrifted.Code(),
							Offset:         event.Offset(),
							PartitionIndex: event.Partition(),
							Payload:        event.Payload,
							FailureMessage: driftedMessage,
						},
						MessageHeaders: event.Headers(),
					},
				)
			}
		}
	}

	if len(dlqEvents) == 0 {
		return nil
	}

	mp.dlqProducer.Produce(dlqEvents)

	telemetry.Count(
		logContext,
		group.MessageProcessor,
		metric.DriftedMessageCount,
		int64(len(dlqEvents)),
		metrics.NewTag(telemetry.OperationIdTag, pkg.DriftedMessagePushOperationId),
	)

	return nil
}
```

can anything be optimized here?

Here are several potential optimizations for this code:

1. **Reduce Map Allocations**:
```go
// Instead of creating new maps frequently, consider pre-allocating with expected capacity
transformers := make(map[string][]transform.Transformer, len(topics))
```

2. **Batch Processing Optimization**:
```go
// Consider using a buffer pool for batch processing to reduce GC pressure
var bufferPool = sync.Pool{
    New: func() interface{} {
        return make([]*transform.MessageModel, 0, initialCapacity)
    },
}
```

3. **Error Handling Consolidation**:
```go
// Create a single error handling function instead of multiple similar ones
func handleError(err error, message string, code errorHandling.ErrorCode) {
    if err != nil {
        panic(errorHandling.Wrap(
            logContext,
            err,
