var messageModelPool = sync.Pool{
    New: func() interface{} {
        return &transform.MessageModel{}
    },
}

// In NewMessageCallback - Get from pool
func (mp *messageProcessor) NewMessageCallback(
    logContext *log.Context,
    tpo *streaming.TopicPartitionOffset,
    key []byte,
    message []byte,
    headers streaming.MessageHeaders,
) {
    // Get from pool
    item := messageModelPool.Get().(*transform.MessageModel)

    // Set the fields
    item.LogContext = logContext
    item.OriginalMessage = &streaming.EventReturn{
        TopicPartitionOffset: tpo,
        MessageHeaders:       headers,
    }
    item.Key = key
    // ... set other necessary fields

    mp.queue.Enqueue(item)
}

// In ProcessMessageBatch - Return to pool after processing
func (mp *messageProcessor) ProcessMessageBatch(
    logContext *log.Context,
    messages []*transform.MessageModel,
) {
    // Defer returning all messages to pool
    defer func() {
        for _, msg := range messages {
            // Clear the message fields
            msg.LogContext = nil
            msg.OriginalMessage = nil
            msg.Key = nil
            msg.Changes = nil
            // ... clear other fields

            // Return to pool
            messageModelPool.Put(msg)
        }
    }()

    // Process the batch as normal
    mp.processMessageBatchInternal(logContext, messages)
}
```

Key points about this implementation:

1. Messages are obtained from the pool when created in NewMessageCallback
2. They are returned to the pool only after being fully processed in ProcessMessageBatch
3. We clear the fields before returning to the pool to prevent memory leaks
4. The pool is package-level so it can be shared across all instances

This way, we maintain the object pooling benefits while respecting the asynchronous nature of the message processing pipeline.

