// NewUemPublicEventTransformer creates a new instance of the Transformer to parse UEM public events.
func NewUemPublicEventTransformer(
	schemaMapper schemaMapping.SchemaMapper,
	ignoreDriftDetection bool,
) Transformer {
	instance := &uemPublicEventTransformer{
		schemaMapper: schemaMapper,
		// reuse VM between re-runs of compiled expressions.
		// https://github.com/expr-lang/expr/blob/master/docs/tips.md
		// THIS IS NOT THREAD SAFE AND MUST LIVE IN THE CONTEXT OF THE OPERATION!!!!
		expressionVM: &vm.VM{},
		UnmarshalOptions: &proto.UnmarshalOptions{
			Merge:          true,
			AllowPartial:   true,
			DiscardUnknown: false,
			Resolver:       protoregistry.GlobalTypes,
		},
		ignoreDriftDetection: ignoreDriftDetection,
	}

	return instance
}

// Transform parsed a serialized UEM public event to MessageModel.
//
// Returns nil if the UEM public event is ignored/unhandled.
func (t *uemPublicEventTransformer) Transform(
	tpo *streaming.TopicPartitionOffset,
	message []byte,
	headers streaming.MessageHeaders,
) (*MessageModel, error) {
	const (
		logSuccessfulTransformDetailMessage = "uem_public_event_transformer.Transform: transformed event details"
		logIgnoringUnmappedPublicEvent      = "uem_public_event_transformer.Transform: ignoring event \"%s\" because no event creator mapping was found"
		errUnexpectedUemEventProtocolFormat = "uem_public_event_transformer.Transform: unexpected uem.event_protocol message format"
		errUnableToParseTimestamp           = "uem_public_event_transformer.Transform: unable to parse event timestamp"
	)

	var (
		event = &streaming.EventReturn{
			TopicPartitionOffset: tpo,
			UemEventProtocol:     &models.UemEventProtocol{},
			MessageHeaders:       headers,
			Payload:              message,
		}
		// deserialize the event envelope
		logContext = log.NewEmptyLogContext(0).
				AddCorrelationId(headers.CorrelationId()).
				AddTenantUuid(headers.TenantUuid()).
				ParseLogContextHeader(headers.LogContext())
		eventName    = event.MessageHeaders.PayloadSchemaName()
		eventCreator func() proto.Message
		ok           bool
	)

	err := proto.Unmarshal(message, event.UemEventProtocol)
	if err != nil {
		return nil, errors.Wrap(err, errUnexpectedUemEventProtocolFormat)
	}

	// we should have an event handler mapped before we could attempt to
	// transform the event.
	if eventCreator, ok = t.schemaMapper.GetPublicSchemaEventCreator(eventName); !ok {
		log.Warnw(
			logContext,
			fmt.Sprintf(logIgnoringUnmappedPublicEvent, eventName),
			event.LoggingFields()...,
		)

		return nil, nil
	}

	// perform basic validation on the message before attempting to transform.
	if !t.verifyEventPayload(event) {
		// this is an event that we are supposed to handle but it's in a bad
		// format, so return an error indicating that its in a bad format.
		return nil, errors.New(errUnexpectedUemEventProtocolFormat)
	}

	// Emit source lag metric.
	timestamp, err := iso8601.ParseString(event.UemEventProtocol.Timestamp)
	if errorHandling.HandleWarning(logContext, errors.Wrap(err, errUnableToParseTimestamp)) == nil {
		telemetry.Timing(
			logContext,
			group.Transformer,
			metric.MessageLag,
			time.Since(timestamp),
			metrics.NewTag(telemetry.TopicTag, tpo.Topic()),
		)
	}

	result, err := t.transformEvent(logContext, eventName, eventCreator, event)
	if err != nil || result == nil {
		return nil, err
	}

	if log.DebugEnabled() {
		log.Debugw(
			logContext,
			logSuccessfulTransformDetailMessage,
			t.getSuccessfulTransformLoggingFields(result)...,
		)
	}

	return result, nil
}

// verifyEventPayload determines whether the event has all the properties we
// need to transform it.
//
// Returns a bool indicating whether the event has the required properties to
// transform.
func (t *uemPublicEventTransformer) verifyEventPayload(
	event *streaming.EventReturn,
) bool {
	return event.UemEventProtocol != nil &&
		event.UemEventProtocol.TenantUuid != "" &&
		event.UemEventProtocol.PayloadSchemaName != "" &&
		len(event.UemEventProtocol.Payload) != 0
}

func (t *uemPublicEventTransformer) transformEvent(
	logContext *log.Context,
	eventName string,
	eventCreator func() proto.Message,
	event *streaming.EventReturn,
) (*MessageModel, error) {
	// parse the events into the index document mappings
	documents, err := t.parseUemPublicEvent(eventName, event, eventCreator().ProtoReflect())
	if err != nil {
		return nil, err
	}

	if documents == nil {
		return nil, nil
	}

	result := &MessageModel{
		LogContext:      log.NewLogContextWithCorrelationIds(event.CorrelationId()).AddTenantUuid(event.TenantUuid()),
		Changes:         documents,
		OriginalMessage: event,
	}

	err = t.postProcessChanges(logContext, result)
	if err != nil {
		return nil, err
	}

	return result, nil
}

func (t *uemPublicEventTransformer) parseUemPublicEvent(
	eventName string,
	event *streaming.EventReturn,
	message protoreflect.Message,
) (IndexKeyToIndexDocumentChangeModelsMap, error) {
	var (
		indexChanges IndexKeyToIndexDocumentChangeModelsMap
		err          error
		eventMapping *schemaMapping.EntityMapping
		found        bool
	)

	if err = proto.Unmarshal(
		event.UemEventProtocol.GetPayload(),
		message.Interface(),
	); err != nil {
		return nil, err
	}

	if eventMapping, found = t.schemaMapper.GetEvent(eventName); !found {
		// any mapped event should also have a respective schema defined
		return nil, errors.Errorf(errSchemaMappingMissingForMappedEvent, eventName)
	}

	if indexChanges, err = t.parseMessage(
		message,
		&entityParseContext{
			op:                     eventMapping.Op,
			event:                  event,
			eventMapping:           eventMapping,
			entityName:             eventName,
			entityMapping:          eventMapping,
			overwriteNilAttributes: false,
		},
	); err != nil {
		return nil, err
	}

	return t.processInterimDocuments(
		event,
		indexChanges,
		eventMapping,
	)
}

func (t *uemPublicEventTransformer) parseMessage(
	message protoreflect.Message,
	context *entityParseContext,
) (IndexKeyToIndexDocumentChangeModelsMap, error) {
	var (
		attributeName    string
		attributeMapping *schemaMapping.AttributeMapping
		finalErr         error
		logContext       = log.NewLogContextWithCorrelationIds(context.event.CorrelationId())
	)

	// Protobuf will panic when a field does not exist.
	// Adding recover to catch the exception and properly log.
	defer errorHandling.Recover(
		logContext,
		nil,
		errorsArg,
		finalErr,
		eventArg,
		context.entityName,
		attributeArg,
		attributeName,
	)

	if !message.IsValid() {
		// We don't need to process entities that are nil.
		return IndexKeyToIndexDocumentChangeModelsMap{}, nil
	}

	var (
		mappedFields = make(IndexKeyToIndexDocumentChangeModelsMap, t.schemaMapper.GetIndexCount())
		fields       = message.Descriptor().Fields()
	)

	for attributeName, attributeMapping = range context.entityMapping.Attributes {
		if err := t.parseAttribute(logContext, mappedFields, &attributeParseContext{
			entityParseContext: context,
			message:            message,
			fields:             fields,
			attributeName:      attributeName,
			attributeMapping:   attributeMapping,
		}); err != nil {
			finalErr = multierror.Append(finalErr, err)
		}
	}

	if finalErr != nil {
		return nil, finalErr
	}

	if context.entityMapping.QueryGenerator != nil {
		for idx, indexChange := range mappedFields {
			generator, exists := context.entityMapping.QueryGenerator[idx]
			if !exists {
				continue
			}

			for _, doc := range indexChange {
				doc.QueryGenerator = generator
			}
		}
	}

	return mappedFields, finalErr
}

func (t *uemPublicEventTransformer) parseAttribute(
	logContext *log.Context,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	// Custom Attributes will cause a panic; do not allow Protobuf to try to look them up.
	if context.attributeMapping.CustomAttribute != nil {
		t.populateCustomAttributeValue(
			&attributeValueMappingContext{
				attributeParseContext: context,
				mappedFields:          mappedFields,
				overwrite:             false,
			},
		)

		return nil
	}

	fieldDescriptor := context.fields.ByTextName(context.attributeName)

	// Yes, field descriptors can be nil.
	// We aren't using oneOfs; sub-messages can be nil.
	// https://github.com/googleapis/google-cloud-python/issues/1402
	if fieldDescriptor == nil {
		const message = "Skipping attribute; has no field descriptor."

		log.Debugw(
			logContext,
			message,
			eventArg,
			context.entityName,
			attributeArg,
			context.attributeName,
		)

		return nil
	}

	value := context.message.Get(fieldDescriptor)

	// We short-circuit a field evaluation under the following conditions:
	// - The field is a scalar
	// - The received value is the scalar's zero value
	// - The field is an enum, or the field has a default value assigned.
	//
	// For enums, this means that a zero value means null.
	if isScalar(context.attributeMapping) && isZeroValue(value, fieldDescriptor) &&
		(isEnum(context.attributeMapping) || hasDefaultValue(context.attributeMapping)) {
		t.mapParsedAttributeValueToDestinations(
			logContext,
			nil,
			&attributeValueMappingContext{
				attributeParseContext: context,
				mappedFields:          mappedFields,
				overwrite:             false,
				isAttributeDeleted:    false,
			},
		)

		return nil
	}

	return t.mapAttribute(
		logContext,
		mappedFields,
		&attributeValueParseContext{
			attributeParseContext: context,
			fieldDescriptor:       fieldDescriptor,
			value:                 value,
		},
	)
}

func (t *uemPublicEventTransformer) mapParsedAttributeValueToDestinations(
	logContext *log.Context,
	parsedValue any,
	context *attributeValueMappingContext,
) {
	// If the value is null, use the default from the schema mapping. The
	// default value priority is: attribute -> destination. The index default is
	// used only when an attribute is deleted.
	if parsedValue == nil && !context.isAttributeDeleted &&
		context.attributeMapping.MapperArguments != nil && context.attributeMapping.MapperArguments.Default != nil {
		parsedValue = context.attributeMapping.MapperArguments.Default
	}

	for _, destination := range t.getDestinations(context.event, context.attributeMapping) {
		t.mapParsedAttributeValueToDestination(logContext, parsedValue, destination, context)
	}
}

func (t *uemPublicEventTransformer) mapParsedAttributeValueToDestination(
	logContext *log.Context,
	parsedValue any,
	destination *schemaMapping.DestinationIndex,
	context *attributeValueMappingContext,
) {
	const message = "Default not configured in mapping; omitting attribute."

	// use default specified by the destination index mapping config if
	// provided.
	if parsedValue == nil && !context.isAttributeDeleted &&
		destination.MapperArguments != nil && destination.MapperArguments.Default != nil {
		parsedValue = destination.MapperArguments.Default
	}

	indexMetadata := t.getIndexMetadata(destination.Index)

	// Assume nil when the attribute is being deleted.
	//
	// If there is an index default we use that value instead.
	if context.isAttributeDeleted {
		parsedValue = nil
		if defaultValue, found := indexMetadata.DefaultValuesMap[destination.Property]; found {
			parsedValue = defaultValue.Value
		}
	}

	isAttributeUpdated := context.isAttributeUpdatedAsPartOfAnArrayItemEntityUpdate &&
		!indexMetadata.SkipNilPropertiesFromUpdates

	// if we still do not have a value then it means the event attribute had
	// no value, and no default was configured for this attribute. We should
	// only set the value to null if the attribute is being deleted or updated.
	if parsedValue == nil && !(context.isAttributeDeleted || isAttributeUpdated) {
		log.Debugw(
			logContext,
			message,
			eventArg,
			context.attributeMapping.EntityName,
			attributeArg,
			context.attributeMapping.Name,
		)

		return
	}

	t.setIndexValue(
		destination.Index,
		destination.Property,
		parsedValue,
		context,
	)
}

func (t *uemPublicEventTransformer) setIndexValue(
	indexName string,
	property string,
	value any,
	context *attributeValueMappingContext,
) {
	var (
		indexMetadata      = t.getIndexMetadata(indexName)
		docs, exists       = context.mappedFields[indexName]
		isMetadataProperty = isPropertyMetadata(indexMetadata, property)
	)

	if !exists {
		docs = make([]*IndexDocumentChangeModel, 0, 1)
	}

	if len(docs) == 0 ||
		!slices.ContainsFunc(docs, func(model *IndexDocumentChangeModel) bool { return model.Op == context.op }) {
		docs = append(
			docs,
			NewIndexDocumentChangeModel(
				context.event,
				context.eventMapping,
				context.op,
				indexName,
				indexMetadata,
				false,
			),
		)
		context.mappedFields[indexName] = docs
	}

	// if there are more than one row for this target index already then this field should be mapped to all rows
	for _, doc := range docs {
		setDocumentValue(doc, property, value, isMetadataProperty, context.overwrite)
	}
}

func (t *uemPublicEventTransformer) mapReferenceAttribute(
	logContext *log.Context,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeValueParseContext,
) error {
	resultValue, err := telemetry.MeasureWithResultAndError(
		log.NewLogContextWithCorrelationIds(context.event.CorrelationId()),
		group.Transformer,
		metric.MapAttributeValue,
		func() (any, error) {
			return t.mapValue(context.attributeMapping, &context.value)
		},
		metrics.NewTag(telemetry.TenantTag, context.event.TenantUuid()),
		metrics.NewTag(telemetry.PayloadSchemaNameTag, context.event.PayloadSchemaName()),
		metrics.NewTag(telemetry.EntityNameTag, context.entityName),
		metrics.NewTag(telemetry.AttributeNameTag, context.attributeName),
		metrics.NewTag(telemetry.MapperNameTag, *context.attributeMapping.Mapper),
	)

	if err != nil {
		return err
	}

	// handle parsing of an individual property of primitive types
	t.mapParsedAttributeValueToDestinations(
		logContext,
		resultValue,
		&attributeValueMappingContext{
			attributeParseContext: context.attributeParseContext,
			mappedFields:          mappedFields,
			overwrite:             true,
			isAttributeUpdatedAsPartOfAnArrayItemEntityUpdate: resultValue == nil && context.overwriteNilAttributes &&
				context.op == updateOperation,
			isAttributeDeleted: false,
		},
	)

	return nil
}

func (t *uemPublicEventTransformer) mapArrayAttribute(
	logContext *log.Context,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeValueParseContext,
) error {
	// protoreflect.List is expected
	if !context.fieldDescriptor.IsList() {
		return errors.Errorf(errInvalidArrayTypeEncountered, context.attributeName)
	}

	arrayItemMappedFields, err := t.parseArrayAttribute(
		logContext,
		context,
	)

	if err != nil {
		return err
	}

	merge(mappedFields, arrayItemMappedFields, false)

	return nil
}

func (t *uemPublicEventTransformer) mapMapAttribute(
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeValueParseContext,
) error {
	// protoreflect.Map is expected
	if !context.fieldDescriptor.IsMap() {
		return errors.Errorf(errInvalidMapTypeEncountered, context.attributeName)
	}

	return t.parseMapAttribute(mappedFields, context)
}

func (t *uemPublicEventTransformer) mapAttribute(
	logContext *log.Context,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeValueParseContext,
) error {
	if context.attributeMapping.Mapper != nil && *context.attributeMapping.Mapper == expressionMapperName {
		return t.parseExpressionAttribute(
			&context.value,
			mappedFields,
			context.attributeParseContext,
		)
	}

	// an attribute could be an entity reference, or an individual property
	if context.attributeMapping.Reflect == nil && context.attributeMapping.Mapper != nil {
		return t.mapReferenceAttribute(
			logContext,
			mappedFields,
			context,
		)
	}

	// parse array of entities
	if *context.attributeMapping.Reflect == arrayTypeRefName {
		return t.mapArrayAttribute(
			logContext,
			mappedFields,
			context,
		)
	}

	// parse a map of entities
	if *context.attributeMapping.Reflect == mapTypeRefName {
		return t.mapMapAttribute(
			mappedFields,
			context,
		)
	}

	// parse nested entity reference by default
	return t.mapNestedEntity(mappedFields, context)
}

func (t *uemPublicEventTransformer) mapNestedEntity(mappedFields IndexKeyToIndexDocumentChangeModelsMap, context *attributeValueParseContext) error {
	nestedEntityMapping, mapped := t.schemaMapper.GetEntity(*context.attributeMapping.Reflect)
	if !mapped {
		// ignore unmapped entities
		return nil
	}

	nestedEntityContext := entityParseContext(*context.entityParseContext)
	nestedEntityContext.entityMapping = nestedEntityMapping
	nestedEntityContext.entityName = *context.attributeMapping.Reflect

	entityMappedFields, err := t.parseMessage(context.value.Message(), &nestedEntityContext)
	if err != nil {
		return err
	}

	merge(mappedFields, entityMappedFields, false)

	return nil
}

func (t *uemPublicEventTransformer) populateCustomAttributeValue(context *attributeValueMappingContext) {
	if context.attributeMapping.CustomAttribute == nil {
		return
	}

	value := context.attributeMapping.CustomAttribute.Value

	// we only have one type to use the event timestamp value
	if context.attributeMapping.CustomAttribute.Type != nil &&
		*context.attributeMapping.CustomAttribute.Type == "from_attribute" &&
		context.attributeMapping.CustomAttribute.Attribute != nil &&
		*context.attributeMapping.CustomAttribute.Attribute == pkg2.TimestampHeader {
		value = context.event.UemEventProtocol.Timestamp
	}

	if value == nil {
		return
	}

	for _, destinationIndex := range t.getDestinations(context.event, context.attributeMapping) {
		t.setIndexValue(
			destinationIndex.Index,
			destinationIndex.Property,
			value,
			context,
		)
	}
}

func (t *uemPublicEventTransformer) parseExpressionAttribute(
	value any,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	const functionName = "uem_public_event_transformer.parseExpressionAttribute"

	var (
		mapperArguments *schemaMapping.MapperArguments
		logContext      = log.NewLogContextWithCorrelationIds(context.event.CorrelationId())
	)

	for _, d := range t.getDestinations(context.event, context.attributeMapping) {
		mapperArguments = context.attributeMapping.MapperArguments

		if d.MapperArguments != nil {
			mapperArguments = d.MapperArguments
		}

		if mapperArguments == nil {
			continue
		}

		result, err := telemetry.MeasureWithResultAndError(
			logContext,
			group.Transformer,
			metric.MapAttributeValue,
			func() (any, error) {
				return t.evaluateExpression(logContext, mapperArguments, value)
			},
			metrics.NewTag(telemetry.TenantTag, context.event.TenantUuid()),
			metrics.NewTag(telemetry.PayloadSchemaNameTag, context.event.PayloadSchemaName()),
			metrics.NewTag(telemetry.EntityNameTag, context.entityName),
			metrics.NewTag(telemetry.AttributeNameTag, context.attributeName),
			metrics.NewTag(telemetry.MapperNameTag, expressionMapperName),
			metrics.NewTag(telemetry.ExpressionMapperNameTag, mapperArguments.Name),
		)

		if err != nil {
			return errors.Wrap(err, functionName)
		}

		t.setIndexValue(
			d.Index,
			d.Property,
			result,
			&attributeValueMappingContext{
				attributeParseContext: context,
				mappedFields:          mappedFields,
				overwrite:             true,
			},
		)
	}

	return nil
}

// evaluateExpression evaluate expression mapping against a given value.
func (t *uemPublicEventTransformer) evaluateExpression(
	logContext *log.Context,
	mapperArguments *schemaMapping.MapperArguments,
	value any,
) (any, error) {
	const expressionMapperNotConfigured = "expression_mapper.evaluateExpression mapper name missing"
	if mapperArguments.Name == "" {
		return nil, errors.New(expressionMapperNotConfigured)
	}

	expression, ok := compliedExpressions[mapperArguments.Name]
	if !ok {
		return nil, errors.New(expressionMapperNotConfigured)
	}

	output, err := t.expressionVM.Run(expression.Program, expression.ValueConverter(value))
	if err != nil {
		_ = errorHandling.HandleError(
			func() *log.Context {
				return logContext
			}, err,
		)
		return nil, err
	}

	return output, nil
}

func (t *uemPublicEventTransformer) parseWrappedArrayAttribute(
	logContext *log.Context,
	wrappedArray protoreflect.ProtoMessage,
	context *attributeParseContext,
) (IndexKeyToIndexDocumentChangeModelsMap, error) {
	mappedFields := make(IndexKeyToIndexDocumentChangeModelsMap, t.schemaMapper.GetIndexCount())

	if context.attributeMapping.Mapper != nil && *context.attributeMapping.Mapper == expressionMapperName {
		err := t.parseExpressionAttribute(
			wrappedArray,
			mappedFields,
			context,
		)

		if err != nil {
			return nil, err
		}

		return mappedFields, nil
	}

	if context.attributeMapping.Items == nil {
		return nil, nil
	}

	getInnerArray, mapped := uemListMessageToArrayMap[*context.attributeMapping.Items]

	if !mapped {
		return nil, nil
	}

	// get the inner array of messages
	messages, err := getInnerArray(wrappedArray)
	if err != nil {
		return nil, err
	}

	for _, message := range messages {
		err := t.parseArrayItem(message, mappedFields, context)
		if err != nil {
			return nil, err
		}
	}

	// In this context, partial documents only make sense for replace operations.
	if context.op == replaceOperation {
		t.generatePartialDocumentsIfConfigured(mappedFields, context)
	}

	trackEntityArrayLength(
		logContext,
		*context.attributeMapping.Items,
		len(messages),
		mappedFields,
		context,
	)

	return mappedFields, nil
}

func (t *uemPublicEventTransformer) generatePartialDocumentsIfConfigured(
	changeModel IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) {
	var (
		itemEntity *schemaMapping.EntityMapping
		found      bool
	)

	if context.attributeMapping.Items == nil {
		// Nothing to do.
		return
	}

	// Partial documents only make sense for an entity with partial document configuration.
	if itemEntity, found = t.schemaMapper.GetEntity(*context.attributeMapping.Items); !found ||
		len(itemEntity.PartialDocumentConfig) == 0 {
		// Nothing to do.
		return
	}

	// Try to add partial documents to the entity's target indices
	for indexKey := range itemEntity.TargetIndices {
		// Add partial document if configuration is found.
		if partialDocConfig, found := itemEntity.PartialDocumentConfig[indexKey]; found {
			var (
				indexMetadata              = t.getIndexMetadata(indexKey)
				applyPartialConfigDefaults = func(doc *IndexDocumentChangeModel, overwrite bool) {
					for name, value := range partialDocConfig.PartialDefaults {
						setDocumentValue(doc, name, value, isPropertyMetadata(indexMetadata, name), overwrite)
					}
				}
			)

			if docs, found := changeModel[indexKey]; found && len(docs) > 0 {
				// Ensure partial defaults.
				updateDocuments(docs, func(doc *IndexDocumentChangeModel) {
					applyPartialConfigDefaults(doc, false)
				})

				// No need to create partial document, the array had documents.
				continue
			}

			partialDoc := NewIndexDocumentChangeModel(
				context.event,
				context.eventMapping,
				context.op,
				indexKey,
				indexMetadata,
				true,
			)
			partialDoc.IsPartialDocument = true
			partialDoc.PartialKey = partialDocConfig.PartialKey
			applyPartialConfigDefaults(partialDoc, true)
			changeModel[indexKey] = append(changeModel[indexKey], partialDoc)
		}
	}
}

func (t *uemPublicEventTransformer) processInterimDocuments(
	event *streaming.EventReturn,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	eventMetadata *schemaMapping.EntityMapping,
) (IndexKeyToIndexDocumentChangeModelsMap, error) {
	const (
		entityNameKey           = "entity_name"
		routingAttributeNameKey = "routing_attribute_name"
	)

	var (
		interimDocs []*IndexDocumentChangeModel
		found       bool
		logContext  *log.Context
	)

	if interimDocs, found = getInterimDocuments(mappedFields); !found {
		// Nothing to do...
		return mappedFields, nil
	}

	removeInterimDocuments(mappedFields)
	logContext = log.NewLogContextWithCorrelationIds(event.CorrelationId())
	if eventMetadata.DestinationSelector == nil {
		log.Debugw(
			logContext,
			"Interim documents were discarded while parsing an event.",
			entityNameKey,
			eventMetadata.Name,
		)
		return mappedFields, nil
	}

	for _, doc := range interimDocs {
		var (
			routingAttributeName = eventMetadata.DestinationSelector.RoutingAttributeName
			routingValue         any
			routingKey           string
			found                bool
			ok                   bool
		)

		if routingValue, found = doc.Properties[routingAttributeName]; !found {
			// Ignoring partial documents with no routing information.
			continue
		}

		if routingKey, ok = routingValue.(string); !ok {
			// Ignoring invalid routing key value.
			log.Warnw(
				logContext,
				"Unexpected routing value type in interim document. The routing attribute must be a string.",
				entityNameKey,
				eventMetadata.Name,
				routingAttributeNameKey,
				routingAttributeName,
			)
			continue
		}

		if destination, found := eventMetadata.DestinationSelector.DestinationRoutes[routingKey]; found {
			t.setPropertiesFromInterimDocument(event, eventMetadata, doc, destination, mappedFields)
		}
	}

	return mappedFields, nil
}

func (t *uemPublicEventTransformer) setPropertiesFromInterimDocument(
	event *streaming.EventReturn,
	eventMetadata *schemaMapping.EntityMapping,
	source *IndexDocumentChangeModel,
	destinationInfo *schemaMapping.DestinationRouteInfo,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
) {
	context := &attributeValueMappingContext{
		attributeParseContext: &attributeParseContext{
			entityParseContext: &entityParseContext{
				event:        event,
				eventMapping: eventMetadata,
			},
		},
		mappedFields: mappedFields,
		overwrite:    false,
	}

	for name, value := range source.Properties {
		if destinationName, found := destinationInfo.SourcePropertyToTargetMap[name]; found {
			context.op = destinationInfo.Op
			t.setIndexValue(
				destinationInfo.IndexName,
				destinationName,
				value,
				context,
			)
		}
	}
}

func getInterimDocuments(mappedFields IndexKeyToIndexDocumentChangeModelsMap) ([]*IndexDocumentChangeModel, bool) {
	interimDocs, found := mappedFields[selectorInterimIndexName]
	return interimDocs, found
}

func removeInterimDocuments(mappedFields IndexKeyToIndexDocumentChangeModelsMap) {
	delete(mappedFields, selectorInterimIndexName)
}

func (t *uemPublicEventTransformer) getIndexMetadata(indexKey string) *schemaMapping.IndexMetadata {
	if indexKey == selectorInterimIndexName {
		return &selectorInterimIndexMetadata
	}

	indexMetadata, _ := t.schemaMapper.GetIndexMetadataByIndexKey(indexKey)

	return indexMetadata
}

func (t *uemPublicEventTransformer) getDestinations(
	event *streaming.EventReturn,
	attributeMapping *schemaMapping.AttributeMapping,
) []*schemaMapping.DestinationIndex {
	var (
		entityMetadata      *schemaMapping.EntityMapping
		found               bool
		destinationSelector *schemaMapping.DestinationSelectorInfo
	)

	if entityMetadata, found = t.schemaMapper.GetEvent(event.PayloadSchemaName()); found {
		destinationSelector = entityMetadata.DestinationSelector
	}

	if destinationSelector != nil {
		// When a destination selector exists, the actual destination of the documents is decided
		// at a later time once all properties have been parsed.
		//
		// This is why the properties are collected in an interim document bucket (selectorInterimIndexName).
		return []*schemaMapping.DestinationIndex{
			{
				Index:    selectorInterimIndexName,
				Property: attributeMapping.Name,
			},
		}
	}

	return attributeMapping.Destinations
}

func (t *uemPublicEventTransformer) parseMapAttribute(
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeValueParseContext,
) error {
	var (
		err  error
		dict = context.value.Map()
	)

	dict.Range(
		func(key protoreflect.MapKey, value protoreflect.Value) bool {
			var (
				propertyName string
				ok           bool
			)

			if propertyName, ok = key.Interface().(string); !ok {
				err = errors.Errorf(
					"unexpected key type while parsing entity '%s', field '%s'",
					context.attributeMapping.EntityName,
					context.attributeMapping.Name,
				)
				return false
			}

			for _, destination := range t.getDestinations(context.event, context.attributeMapping) {
				t.setIndexValue(
					destination.Index,
					propertyName,
					value.Interface(),
					&attributeValueMappingContext{
						attributeParseContext: context.attributeParseContext,
						mappedFields:          mappedFields,
						overwrite:             false,
					},
				)
			}

			return true
		},
	)

	return err
}

func (t *uemPublicEventTransformer) parseArrayAttribute(
	logContext *log.Context,
	context *attributeValueParseContext,
) (IndexKeyToIndexDocumentChangeModelsMap, error) {
	// special handling for []event_ns.attribute_change
	if context.attributeMapping.Items != nil && *context.attributeMapping.Items == pkg.AttributeChangeEventName {
		return t.parseAttributeChanges(logContext, context)
	}

	mappedFields := make(IndexKeyToIndexDocumentChangeModelsMap, t.schemaMapper.GetIndexCount())
	list := context.value.List()
	count := list.Len()

	for i := 0; i < count; i++ {
		message := list.Get(i).Message().Interface()

		err := t.parseArrayItem(message, mappedFields, context.attributeParseContext)
		if err != nil {
			return nil, err
		}
	}

	// In this context, partial documents only make sense for snapshot events and CREATE OP.
	//
	// The reason is FullState events are processed as attribute change events, that means, their
	// execution path never reaches this part of the code.
	if context.event.IsSnapshotEvent() && context.op == createOperation {
		t.generatePartialDocumentsIfConfigured(mappedFields, context.attributeParseContext)
	}

	if context.attributeMapping.Items != nil {
		trackEntityArrayLength(
			logContext,
			*context.attributeMapping.Items,
			count,
			mappedFields,
			context.attributeParseContext,
		)
	}

	return mappedFields, nil
}

func trackEntityArrayLength(
	logContext *log.Context,
	entityName string,
	arrayLength int,
	changeModel IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) {
	telemetry.Gauge(
		logContext,
		group.Transformer,
		metric.EntityArraySize,
		float64(arrayLength),
		metrics.NewTag(telemetry.EntityNameTag, entityName),
		metrics.NewTag(telemetry.TenantTag, context.event.TenantUuid()),
		metrics.NewTag(telemetry.PayloadSchemaNameTag, context.event.PayloadSchemaName()),
	)

	arrayLengthTagValue := strconv.Itoa(arrayLength)
	targetIndices := make([]string, 0, len(changeModel))
	for index := range changeModel {
		targetIndices = append(targetIndices, index)

		// Emit target index specific metric.
		telemetry.Gauge(
			logContext,
			group.Transformer,
			metric.EntityArrayIndexDocCount,
			float64(len(changeModel[index])),
			metrics.NewTag(telemetry.EntityNameTag, entityName),
			metrics.NewTag(telemetry.TenantTag, context.event.TenantUuid()),
			metrics.NewTag(telemetry.PayloadSchemaNameTag, context.event.PayloadSchemaName()),
			metrics.NewTag(telemetry.IndexNameTag, index),
			metrics.NewTag("entity_array_length", arrayLengthTagValue),
		)
	}

	if arrayLength >= entityArrayLengthLoggingThreshold {
		log.Warnw(
			logContext,
			"Entity array length exceeds threshold.",
			log.EntityNameKey,
			entityName,
			log.ArrayLengthKey,
			arrayLength,
			log.PayloadSchemaNameKey,
			context.event.PayloadSchemaName(),
			"target_indices",
			targetIndices,
		)
	}
}

func (t *uemPublicEventTransformer) parseArrayItem(
	message proto.Message,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	if context.attributeMapping.Items == nil {
		return nil
	}
	entityMapping, mapped := t.schemaMapper.GetEntity(*context.attributeMapping.Items)
	if !mapped {
		return nil
	}

	entityContext := entityParseContext(*context.entityParseContext)
	entityContext.entityName = *context.attributeMapping.Items
	entityContext.entityMapping = entityMapping
	entityContext.overwriteNilAttributes = true

	itemMappedFields, err := t.parseMessage(
		message.ProtoReflect(),
		&entityContext,
	)
	if err != nil {
		return err
	}

	isEntityArray := !isRootField(context.attributeMapping)

	// every item is a new doc
	for idx, indexChange := range itemMappedFields {
		if isEntityArray {
			updateDocuments(indexChange, func(doc *IndexDocumentChangeModel) {
				doc.isStandaloneDocument = true
			})
		}

		if mappedFields[idx] == nil {
			mappedFields[idx] = indexChange
			continue
		}

		mappedFields[idx] = append(mappedFields[idx], indexChange...)
	}

	return nil
}

// parseAttributeChanges parses an array of event_ns.attribute_change.
//
// The []event_ns.attribute_change define individual attribute changes for one
// or more entities.
//
// Every event_ns.attribute_change defines which attribute has changed, the
// operation type and the new value. The value itself is proto serialized, and
// needs to be deserialized to it's appropriate type before it could be mapped.
//
// The array types are also not an array but a wrapped proto message which
// contains the array of items.
//
// Ex: List_DeviceApplication contains Items []DeviceApplication. So the array
// of items need to be extracted before it could be parsed as other arrays.
//
// Instead of defining complicated mapping to handle event_ns.attribute_change,
// we are opting for a hardcoded logic because it's simpler to implement than
// developing complex mapping syntax for it. The structure of
// event_ns_attribute_change is pretty fundamental to the V2 events, and most
// likely won't see any breaking changes (🤞).
func (t *uemPublicEventTransformer) parseAttributeChanges(
	logContext *log.Context,
	context *attributeValueParseContext,
) (IndexKeyToIndexDocumentChangeModelsMap, error) {
	var (
		consolidatedError   error
		attributeChangeList = context.value.List()
		rootFields          = make(IndexKeyToIndexDocumentChangeModelsMap, t.schemaMapper.GetIndexCount())
		entityArrays        = make(IndexKeyToIndexDocumentChangeModelsMap, t.schemaMapper.GetIndexCount())
	)

	traverseList(
		attributeChangeList,
		func(message protoreflect.ProtoMessage) {
			attributeChangeMessage, ok := message.(*models.EventAttributeChange)
			if !ok {
				return
			}

			attributeMapping, mapped := t.schemaMapper.GetAttribute(attributeChangeMessage.AttributeReference)
			if !mapped {
				return
			}

			if isRootField(attributeMapping) {
				// Process root fields.
				consolidatedError = t.parseAttributeChange(
					logContext,
					context,
					attributeChangeMessage,
					attributeMapping,
					rootFields,
					consolidatedError,
				)
			} else {
				// Process entity array fields.
				entityArrayDocs := make(IndexKeyToIndexDocumentChangeModelsMap, t.schemaMapper.GetIndexCount())

				consolidatedError = t.parseAttributeChange(
					logContext,
					context,
					attributeChangeMessage,
					attributeMapping,
					entityArrayDocs,
					consolidatedError,
				)

				entityArrays.copyAllDocuments(entityArrayDocs)
			}
		},
	)

	entityArrays.merge(rootFields, false)
	rootFields.copyAllDocuments(entityArrays)
	return rootFields, consolidatedError
}

func (t *uemPublicEventTransformer) parseAttributeChange(
	logContext *log.Context,
	context *attributeValueParseContext,
	attributeChangeMessage *models.EventAttributeChange,
	attributeMapping *schemaMapping.AttributeMapping,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	finalErr error,
) error {
	const (
		functionName = "uem_public_event_transformer.parseAttributeChange"
		format       = "Unable to map %s for %s with value: %s"
	)

	var (
		isDocumentGeneratingAttribute = true
		changeType                    = attributeChangeMessage.ChangeType.String()
		attributeOp                   = strings.TrimPrefix(changeType, attributeChangeTypeEnumPrefix)
		itemEntityParseContext        = entityParseContext(*context.entityParseContext)
		itemAttributeParseContext     = &attributeParseContext{
			entityParseContext: &itemEntityParseContext,
			attributeName:      attributeChangeMessage.AttributeReference,
			attributeMapping:   attributeMapping,
		}
	)

	itemEntityParseContext.op = attributeOp
	if isRootField(attributeMapping) {
		// For non-document generating attributes, we always go with an update operation. There
		// is no scalar or object attribute operation that should result in anything else than
		// a document upsert.
		//
		// This applies even when the desired attribute change operation is deleted. In those
		// delete use cases, we really want to set the field to its null value, not deleting the
		// whole document.
		itemEntityParseContext.op = updateOperation
		isDocumentGeneratingAttribute = false
	}

	if err := t.parseItemAttributeChange(
		logContext,
		attributeChangeMessage,
		attributeOp,
		isDocumentGeneratingAttribute,
		mappedFields,
		itemAttributeParseContext,
	); err != nil {
		finalErr = errors.Wrap(
			multierror.Append(
				finalErr,
				errors.WithMessagef(
					err,
					format,
					attributeChangeMessage.AttributeReference,
					context.event.UemEventProtocol.PayloadUniqueKey,
					hex.EncodeToString(attributeChangeMessage.Value),
				),
			),
			functionName,
		)
	}

	return finalErr
}

func (t *uemPublicEventTransformer) parseItemAttributeChange(
	logContext *log.Context,
	attributeChangeMessage *models.EventAttributeChange,
	attributeOp string,
	isDocumentGeneratingAttribute bool,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	// primitive data types
	if context.attributeMapping.Mapper != nil && context.attributeMapping.Reflect == nil {

		return t.parseScalarAttributeChange(
			logContext,
			attributeChangeMessage,
			attributeOp,
			mappedFields,
			context,
		)
	}

	// attribute is an array
	if *context.attributeMapping.Reflect == arrayTypeRefName {
		return t.parseArrayAttributeChange(
			logContext,
			attributeChangeMessage,
			isDocumentGeneratingAttribute,
			mappedFields,
			context,
		)
	}

	return t.parseEntityAttributeChange(
		attributeChangeMessage,
		isDocumentGeneratingAttribute,
		mappedFields,
		context,
	)
}

func (t *uemPublicEventTransformer) parseScalarAttributeChange(
	logContext *log.Context,
	attributeChangeMessage *models.EventAttributeChange,
	attributeOp string,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	value, err := telemetry.MeasureWithResultAndError(
		log.NewLogContextWithCorrelationIds(context.event.CorrelationId()),
		group.Transformer,
		metric.MapAttributeValue,
		func() (any, error) {
			return t.mapByteStringToValue(context.attributeMapping, attributeChangeMessage.Value)
		},
		metrics.NewTag(telemetry.TenantTag, context.event.TenantUuid()),
		metrics.NewTag(telemetry.PayloadSchemaNameTag, context.event.PayloadSchemaName()),
		metrics.NewTag(telemetry.EntityNameTag, context.entityName),
		metrics.NewTag(telemetry.AttributeNameTag, attributeChangeMessage.AttributeReference),
		metrics.NewTag(telemetry.MapperNameTag, *context.attributeMapping.Mapper),
	)

	if err != nil {
		return err
	}

	t.mapParsedAttributeValueToDestinations(
		logContext,
		value,
		&attributeValueMappingContext{
			attributeParseContext: context,
			mappedFields:          mappedFields,
			overwrite:             true,
			isAttributeDeleted: attributeOp == deleteOperation &&
				(context.attributeMapping.Reflect == nil ||
					*context.attributeMapping.Reflect != arrayTypeRefName),
		},
	)

	return nil
}

func (t *uemPublicEventTransformer) parseArrayAttributeChange(
	logContext *log.Context,
	attributeChangeMessage *models.EventAttributeChange,
	isDocumentGeneratingAttribute bool,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	// convert byte string to wrapped array message
	var parser uemEntityPayloadParser
	parser, mapped := uemListMessageParserMap[*context.attributeMapping.Items]

	if !mapped {
		return nil
	}

	var arrayItemMappedFields IndexKeyToIndexDocumentChangeModelsMap
	// a wrapped message with inner array of types is expected
	wrappedArray, err := parser(attributeChangeMessage.Value)
	if err != nil {
		return err
	}

	arrayItemMappedFields, err = t.parseWrappedArrayAttribute(
		logContext,
		wrappedArray,
		context,
	)

	if err != nil {
		return err
	}

	merge(mappedFields, arrayItemMappedFields, isDocumentGeneratingAttribute)

	return nil
}

func (t *uemPublicEventTransformer) parseEntityAttributeChange(
	attributeChangeMessage *models.EventAttributeChange,
	isDocumentGeneratingAttribute bool,
	mappedFields IndexKeyToIndexDocumentChangeModelsMap,
	context *attributeParseContext,
) error {
	// attribute maps to an entity
	// unmarshal the byte string in to an entity
	entityMapping, mapped := t.schemaMapper.GetEntity(*context.attributeMapping.Reflect)
	if !mapped {
		// ignore unmapped entities
		return nil
	}

	entityParser, mapped := uemEntityParserMap[*context.attributeMapping.Reflect]
	if !mapped {
		// ignore entities that can't be parsed
		return nil
	}

	entityMessage, err := entityParser(attributeChangeMessage.Value)
	if err != nil {
		return err
	}

	entityContext := entityParseContext(*context.entityParseContext)
	entityContext.entityName = *context.attributeMapping.Reflect
	entityContext.entityMapping = entityMapping
	entityContext.overwriteNilAttributes = false

	mappedEntityFields, err := t.parseMessage(
		entityMessage.ProtoReflect(),
		&entityContext,
	)
	if err != nil {
		return err
	}

	merge(mappedFields, mappedEntityFields, isDocumentGeneratingAttribute)

	return nil
}

func merge(
	target IndexKeyToIndexDocumentChangeModelsMap,
	source IndexKeyToIndexDocumentChangeModelsMap,
	isDocumentGeneratingEvent bool,
) {
	if source == nil {
		return
	}

	for sourceIndexName, sourceDocs := range source {
		mergeIndexDocuments(sourceIndexName, sourceDocs, target[sourceIndexName], isDocumentGeneratingEvent, target)
	}
}

func mergeIndexDocuments(
	sourceIndexName string,
	sourceDocs, targetDocs []*IndexDocumentChangeModel,
	isDocumentGeneratingEvent bool,
	target IndexKeyToIndexDocumentChangeModelsMap,
) {
	var (
		sourceDocsLen = len(sourceDocs) // len of a nil slice is zero by definition.
		targetDocsLen = len(targetDocs) // len of a nil slice is zero by definition.
	)

	// If no source documents, nothing to do.
	if sourceDocsLen == 0 {
		return
	}

	// if the target doesn't have this index then we just take all the docs from source
	if targetDocsLen == 0 {
		target[sourceIndexName] = sourceDocs
		return
	}

	// Since we are merging documents from the same overarching entity, use the query generator from the first item...
	sourceDoc := sourceDocs[0]
	updateDocuments(targetDocs, func(doc *IndexDocumentChangeModel) {
		doc.QueryGenerator = sourceDoc.QueryGenerator
	})

	// if both source and target have single record (which will be the case when we are not flatting arrays)
	// source properties should be copied over to the target or the source docs should be appended if the
	// source event was document generating.
	//
	// if the target doc is a standalone document, no action should be attempted.
	targetDoc := targetDocs[0]
	if sourceDocsLen == 1 && targetDocsLen == 1 && !targetDoc.isStandaloneDocument {
		if isDocumentGeneratingEvent {
			// append the new docs from source to target
			target[sourceIndexName] = append(target[sourceIndexName], sourceDocs...)
		} else {
			mergeDoc(targetDocs[0], sourceDoc, true)
		}

		return
	}

	// copy over any properties already parsed (coming from parent attributes) in target to source
	if targetDocsLen != 0 {
		updateDocuments(sourceDocs, func(doc *IndexDocumentChangeModel) {
			mergeDoc(doc, targetDoc, false)
		})
	}

	// if source has more rows than the target (source was probably an array which got flattened)
	// in this case target we can copy over target[0] (top level properties would be here)
	// properties to source docs and replace the target index.
	//
	// if the target is a stand alone document, then two entity arrays are targeting the same
	// index, we should not replace the target docs.
	if (sourceDocsLen > targetDocsLen) && !targetDoc.isStandaloneDocument {
		target[sourceIndexName] = sourceDocs
		return
	}

	// append the new docs from source to target
	target[sourceIndexName] = append(target[sourceIndexName], sourceDocs...)
}

func updateDocuments(docs []*IndexDocumentChangeModel, updateFunc func(*IndexDocumentChangeModel)) {
	for _, doc := range docs {
		updateFunc(doc)
	}
}

func mergeDoc(target *IndexDocumentChangeModel, source *IndexDocumentChangeModel, overwrite bool) {
	if overwrite {
		target.Op = source.Op
		target.isStandaloneDocument = source.isStandaloneDocument
		target.IsPartialDocument = source.IsPartialDocument
		target.PartialKey = source.PartialKey
	}

	target.MergeProperties(source, overwrite)
}

// getSuccessfulTransformLoggingFields get logging fields in key,
// value pairs to log information about the transformed output and the message headers.
/*
	...
	"changes": {
		"index-name": [
			{
				"op": "UPSERT",
				"properties": ["tenant_uuid", "device_uuid"],
				"key": {
					"tenant_uuid": "value",
					"device_uuid": "value"
				}
			}
		]
	},
	... message headers ...
*/
func (t *uemPublicEventTransformer) getSuccessfulTransformLoggingFields(message *MessageModel) []interface{} {
	const changesFieldName = "changes"
	var (
		headerFields = message.OriginalMessage.LoggingFields()
		fields       = make([]interface{}, 0, len(headerFields)+1)
	)

	fields = append(fields, changesFieldName, message.Changes.GetIndexChangesValueForLogging(t.schemaMapper))

	return append(fields, headerFields...)
}

// isZeroValue checks if a protobuf value is equal to the default value of a given field.
func isZeroValue(value protoreflect.Value, fieldDescriptor protoreflect.FieldDescriptor) bool {
	return fieldDescriptor.Default().Equal(value)
}

// isEnum returns true if the attribute metadata belongs to an enum. It returns false otherwise.
func isEnum(attributeMapping *schemaMapping.AttributeMapping) bool {
	return attributeMapping.Mapper != nil && *attributeMapping.Mapper == enumToString
}

// isScalar returns true if the attribute metadata belongs to a scalar value (int, float, string, enum, etc.). It returns false otherwise.
func isScalar(attributeMapping *schemaMapping.AttributeMapping) bool {
	return attributeMapping.Reflect == nil
}

// hasDefaultValue returns true if the attribute metadata has a default value (other than nil) defined. It returns false otherwise.
func hasDefaultValue(attributeMapping *schemaMapping.AttributeMapping) bool {
	return attributeMapping.MapperArguments != nil && attributeMapping.MapperArguments.Default != nil
}

// isPropertyMetadata determines if a given property should be considered metadata. A property is considered metadata when it is not
// included in the definition of the target index.
func isPropertyMetadata(targetIndexMetadata *schemaMapping.IndexMetadata, propertyName string) bool {
	_, found := targetIndexMetadata.EventMetadataProperties[propertyName]
	return found
}

// setDocumentValue sets a document value. It uses the right property bag depending if the property is metadata or not.
func setDocumentValue(
	doc *IndexDocumentChangeModel,
	propertyName string,
	propertyValue any,
	isMetadata bool,
	overwrite bool,
) {
	if isMetadata {
		doc.EventMetadata[propertyName] = propertyValue
		return
	}

	// do not overwrite if asked to do so. (Useful to map required defaults)
	if _, exists := doc.Properties[propertyName]; !overwrite && exists {
		return
	}

	doc.Properties[propertyName] = propertyValue
}

// traverseList iterates over a proto-reflect list.
func traverseList(list protoreflect.List, action func(protoreflect.ProtoMessage)) {
	count := list.Len()
	for idx := 0; idx < count; idx++ {
		action(list.Get(idx).Message().Interface())
	}
}

// isRootField returns true if the given attribute mapping is a root field; false otherwise.
func isRootField(attributeMapping *schemaMapping.AttributeMapping) bool {
	return attributeMapping.Reflect == nil || *attributeMapping.Reflect != arrayTypeRefName || attributeMapping.Mapper != nil
}
