1. First, let's optimize the map allocations with a size-based pool system:

```go
// Package level pools for different sized maps
type mapPool struct {
    pools map[int]*sync.Pool
    mu    sync.RWMutex
}

var (
    propertiesMapPool = newMapPool()
    metadataMapPool  = newMapPool()
)

func newMapPool() *mapPool {
    return &mapPool{
        pools: make(map[int]*sync.Pool),
    }
}

func (p *mapPool) Get(size int) map[string]interface{} {
    // Round up to nearest power of 2 for better reuse
    size = nextPowerOf2(size)

    p.mu.RLock()
    pool, exists := p.pools[size]
    p.mu.RUnlock()

    if !exists {
        p.mu.Lock()
        pool, exists = p.pools[size]
        if !exists {
            pool = &sync.Pool{
                New: func() interface{} {
                    return make(map[string]interface{}, size)
                },
            }
            p.pools[size] = pool
        }
        p.mu.Unlock()
    }

    m := pool.Get().(map[string]interface{})
    return m
}

func (p *mapPool) Put(m map[string]interface{}) {
    size := nextPowerOf2(len(m))

    // Clear the map
    for k := range m {
        delete(m, k)
    }

    p.mu.RLock()
    pool := p.pools[size]
    p.mu.RUnlock()

    pool.Put(m)
}

func nextPowerOf2(v int) int {
    v--
    v |= v >> 1
    v |= v >> 2
    v |= v >> 4
    v |= v >> 8
    v |= v >> 16
    v++
    return v
}
```

