type ModelPool struct {
    pool    chan *IndexDocumentChangeModel
    size    int
    created int64 // for monitoring
}

func NewModelPool(size int) *ModelPool {
    return &ModelPool{
        pool: make(chan *IndexDocumentChangeModel, size),
        size: size,
    }
}

func (p *ModelPool) Get(expectedPropSize int) *IndexDocumentChangeModel {
    select {
    case model := <-p.pool:
        return model
    default:
        atomic.AddInt64(&p.created, 1)
        return &IndexDocumentChangeModel{
            Properties:    propertiesMapPool.Get(expectedPropSize),
            EventMetadata: metadataMapPool.Get(4), // typical metadata size
        }
    }
}

func (p *ModelPool) Put(model *IndexDocumentChangeModel) {
    // Clear the model
    model.Op = ""
    model.IndexMetadata = nil

    // Return maps to their pools
    propertiesMapPool.Put(model.Properties)
    metadataMapPool.Put(model.EventMetadata)

    // Get fresh maps for next use
    model.Properties = propertiesMapPool.Get(len(model.Properties))
    model.EventMetadata = metadataMapPool.Get(4)

    select {
    case p.pool <- model:
        // Successfully returned to pool
    default:
        // Pool is full, let GC handle it
    }
}
