func measureMemoryUsage(logContext *log.Context, label string, f func()) {
    // Before measurements
    var m1, m2 runtime.MemStats
    runtime.ReadMemStats(&m1)

    // Create memory profile before
    beforeFile, _ := os.Create(fmt.Sprintf("memprofile_%s_before.pprof", label))
    pprof.WriteHeapProfile(beforeFile)
    beforeFile.Close()

    // Run the function
    f()

    // After measurements
    runtime.ReadMemStats(&m2)

    // Create memory profile after
    afterFile, _ := os.Create(fmt.Sprintf("memprofile_%s_after.pprof", label))
    pprof.WriteHeapProfile(afterFile)
    afterFile.Close()

    // Log the differences
    log.Infow(logContext, 
        fmt.Sprintf("Memory usage for %s", label),
        "alloc_bytes_diff", m2.TotalAlloc - m1.TotalAlloc,
        "sys_bytes_diff", m2.Sys - m1.Sys,
        "mallocs_diff", m2.Mallocs - m1.Mallocs,
        "frees_diff", m2.Frees - m1.Frees,
        "gc_cycles", m2.NumGC - m1.NumGC,
    )
}
