	reporter "github.com/syntaqx/go-metrics-datadog"
)

const defaultAgentAddress string = "localhost:8125"
const defaultMetricRateConfigValue string = "1.0" // send always! (no sampling)
const defaultMetricRate float64 = 1.0             // send always! (no sampling)

// Pseudo boolean values
const (
	yes int64 = 1
	no  int64 = 0
)

// Supported metric types
const (
	counterType = metrics.CounterType
	gaugeType   = metrics.GaugeType
	measureType = metrics.MeasureType
)

// Custom config tags
const (
	// configRateName labels the configured rate the metric is supposed
	// to be sent to the server. By default, datadog.rate is 1.0 (always)
	configRateName string = "datadog.rate"
)

// TagsSeparator is the character used to separate tags definitions.
const TagsSeparator string = ","

// datadogTags interprets the label/value pairs as tags.
//
// It provides a convenient flatten() method to format the tags
// the way the datadog library expects.
type datadogTags []metrics.Tag

type datadogMetric struct {
	name   string
	rate   float64
	tags   datadogTags
	group  metrics.Group
	client *statsd.Client
}

type datadogCounter datadogMetric
type datadogGauge datadogMetric
type datadogTimer datadogMetric

type datadogMetricGroup struct {
	enabled  atomic.Int64
	counters map[string]*datadogCounter
	gauges   map[string]*datadogGauge
	timers   map[string]*datadogTimer
}

type datadogRegistry struct {
	groups map[string]*datadogMetricGroup
	client *statsd.Client
	conf   *config.Registry
}

var errDatadogNilConfigError = errors.New("unable to create a datadog metrics registry; the configuration is null")

// NewRegistry creates a new datadog metrics registry.
func NewRegistry(
	logContext *log.Context,
	registryConfig *config.Registry,
	additionalTags *string,
) (metrics.Registry, error) {
	if registryConfig == nil {
		return nil, errDatadogNilConfigError
	}

	addr := env.LookupValue(AgentAddress, defaultAgentAddress)

	// The statsd.WithoutTelemetry() option prevents datadog client telemetry generation.
	// The statsd.WithoutOriginDetection() option prevents adding the client id
	// to the metric. Telegraf does not support datadog protocol v1.2, so this
	// will result in a parsing failure.
	// https://github.com/influxdata/telegraf/issues/12991
	client, err := statsd.New(addr, statsd.WithoutTelemetry(), statsd.WithoutOriginDetection())
	if err != nil {
		return nil, err
	}

	registry := &datadogRegistry{
		groups: make(map[string]*datadogMetricGroup, len(registryConfig.Groups)),
		client: client,
		conf:   registryConfig,
	}

	globalTags := registryConfig.GetGlobalTags(logContext, TagsSeparator)

	for groupName, groupConfig := range registryConfig.Groups {
		group := &datadogMetricGroup{
			counters: make(map[string]*datadogCounter),
			gauges:   make(map[string]*datadogGauge),
			timers:   make(map[string]*datadogTimer),
		}

		group.SetEnabled(groupConfig.IsEnabled(logContext))
		for metricName, metricConfig := range groupConfig.Metrics {
			metric := &datadogMetric{
				name: registryConfig.GetMetricFullName(logContext, groupName, metricName),
				rate: getMetricRateFromConfig(
					logContext,
					metricName,
					registryConfig.Config,
					groupConfig.Config,
					metricConfig.Config,
				),
				tags: getMetricTagsFromConfig(
					logContext,
					metricName,
					globalTags,
					additionalTags,
					groupConfig.Config,
					metricConfig.Config,
				),
				group:  group,
				client: client,
			}

			switch metricConfig.Type {
			case counterType:
				group.counters[metricName] = (*datadogCounter)(metric)
			case gaugeType:
				group.gauges[metricName] = (*datadogGauge)(metric)
			case measureType:
				baseName := metric.name
				timerName := registryConfig.JoinMetricNames(logContext, metricName, metrics.MeasureLatencySuffix)
				callCounterName := registryConfig.JoinMetricNames(
					logContext, metricName,
					metrics.MeasureCallCounterSuffix,
				)
				failureCounterName := registryConfig.JoinMetricNames(
					logContext, metricName,
					metrics.MeasureFailureCounterSuffix,
				)

				// Setup time metric...
				timer := *metric
				timer.name = registryConfig.JoinMetricNames(logContext, baseName, metrics.MeasureLatencySuffix)
				group.timers[timerName] = (*datadogTimer)(&timer)

				// Setup call counter...
				callCounter := *metric
				callCounter.name = registryConfig.JoinMetricNames(
					logContext, baseName,
					metrics.MeasureCallCounterSuffix,
				)
				group.counters[callCounterName] = (*datadogCounter)(&callCounter)

				// Setup failure counter...
				metric.name = registryConfig.JoinMetricNames(
					logContext, baseName,
					metrics.MeasureFailureCounterSuffix,
				)
				group.counters[failureCounterName] = (*datadogCounter)(metric)

			default:
				log.Errorf(
					logContext,
					"ERROR: metric configuration error. Unknown metric type '%s'. The metric '%s' was ignored.",
					metricConfig.Type,
					metricName,
				)
			}
		}

		registry.groups[groupName] = group
	}

	return registry, nil
}

// GetConfig retrieves a registry's configuration.
//
// Please note that modifications to the returned object will
// not result in behavior changes. The response should be
// used as readonly.
func (registry *datadogRegistry) GetConfig() *config.Registry {
	return registry.conf
}

// GetGroup retrieves a metrics group with the given name. If the group is not found it panics.
func (registry *datadogRegistry) GetGroup(logContext *log.Context, name string) metrics.Group {
	group, ok := registry.LookupGroup(name)
	if !ok {
		log.Panicf(logContext, "ERROR: group '%s' was not found", name)
	}

	return group
}

// LookupGroup looks up a group of metrics with the given name. If the group is not found, it
// returns nil and false; if the group is found, it returns the group and true.
func (registry *datadogRegistry) LookupGroup(name string) (metrics.Group, bool) {
	group, ok := registry.groups[name]
	return group, ok
}

// SubscribeToAdditionalRegistries creates metric reporter to subscribe to additional registries.
func (registry *datadogRegistry) SubscribeToAdditionalRegistries(
	logContext *log.Context,
	prefix string,
	registries ...goMetrics.Registry,
) ([]metrics.Reporter, error) {
	var (
		addr      = env.LookupValue(AgentAddress, defaultAgentAddress)
		namespace = fmt.Sprintf(
			"%s%s",
			registry.GetConfig().JoinMetricNames(logContext, registry.GetConfig().GetPrefix(), prefix),
			registry.GetConfig().GetSeparator(),
		)
		globalTags = strings.Split(registry.GetConfig().GetGlobalTags(logContext, TagsSeparator), TagsSeparator)
		reporters  = make([]metrics.Reporter, 0, len(registries))
	)

	for _, additionalRegistry := range registries {
		additionalReporter, err := reporter.NewReporter(
			additionalRegistry, addr,
			reporter.UseFlushInterval(time.Second*10),
			reporter.UsePercentiles([]float64{0.50, 0.90, 0.99}),
		)

		if err != nil {
			return nil, err
		}

		additionalReporter.Client.Namespace = namespace
		additionalReporter.Client.Tags = append(additionalReporter.Client.Tags, globalTags...)
		reporters = append(reporters, additionalReporter)

		go additionalReporter.Flush()
	}

	return reporters, nil
}

// Close closes the registry.
func (registry *datadogRegistry) Close() error {
	return registry.client.Close()
}

func getMetricRateFromConfig(
	logContext *log.Context,
	name string,
	registryConfig, groupConfig, metricConfig map[string]string,
) float64 {
	rateValue :=
		config.GetValue(
			metricConfig, configRateName,
			config.GetValue(
				groupConfig, configRateName,
				config.GetValue(registryConfig, configRateName, defaultMetricRateConfigValue),
			),
		)

	rate, err := strconv.ParseFloat(rateValue, 64)
	if err != nil {
		log.Errorf(
			logContext,
			"ERROR: metric configuration error. Unable to parse metric '%s' rate value. Using default (1.0).",
			name,
		)
		return defaultMetricRate
	}

	if rate > 1.0 {
		log.Errorw(
			logContext,
			"ERROR: metric configuration error. Metric '%s' rate value is out of range. Using default (1.0).",
			name,
		)
		return defaultMetricRate
	}

	if rate < 0 {
		log.Errorw(
			logContext,
			"ERROR: metric configuration error. Metric '%s' rate value is negative. "+
				"Using zero (0.0).", name,
		)
		return 0
	}

	return rate
}

func getMetricTagsFromConfig(
	logContext *log.Context,
	name, globalTags string,
	additionalTags *string,
	groupConfig, metricConfig map[string]string,
) datadogTags {
	configuredTags := make([]string, 0, 3)
	if len(globalTags) > 0 {
		configuredTags = append(configuredTags, globalTags)
	}

	if additionalTags != nil && len(*additionalTags) > 0 {
		configuredTags = append(configuredTags, *additionalTags)
	}

	groupTags := config.GetTags(groupConfig)
	if len(groupTags) > 0 {
		configuredTags = append(configuredTags, groupTags)
	}

	metricTags := config.GetTags(metricConfig)
	if len(metricTags) > 0 {
		configuredTags = append(configuredTags, metricTags)
	}

	flattenedTags := strings.Join(configuredTags, TagsSeparator)

	tagValues := strings.Split(flattenedTags, TagsSeparator)
	result := make([]metrics.Tag, 0, len(tagValues))
	for _, tagValue := range tagValues {
		tagComponents := strings.Split(tagValue, ":")
		switch componentCount := len(tagComponents); componentCount {
		case 1:
			if len(tagComponents[0]) > 0 {
				result = append(result, metrics.Tag{Name: tagComponents[0]})
			} else {
				log.Errorf(
					logContext,
					"ERROR: metric configuration error. Empty tag of metric '%s' has been ignored.",
					name,
				)
			}
		case 2:
			if len(tagComponents[0]) > 0 && len(tagComponents[1]) > 0 {
				result = append(
					result, metrics.Tag{
						Name:  tagComponents[0],
						Value: tagComponents[1],
					},
				)
			} else {
				log.Errorf(
					logContext,
					"ERROR: metric configuration error. Malformed tag '%s' of metric '%s' has been ignored.",
					tagValue,
					name,
				)
			}
		default:
			log.Errorf(
				logContext,
				"ERROR: metric configuration error. Unable to parse tag '%s' of metric '%s'.",
				tagValue,
				name,
			)
		}
	}
	return result
}

func (tags datadogTags) flatten() []string {
	var (
		flattenedTag string
		result       = make([]string, 0, len(tags))
		builder      strings.Builder
	)

	for _, pair := range tags {
		if len(pair.Value) == 0 {
			flattenedTag = pair.Name
		} else {
			const separator = ":"
			builder.Grow(len(pair.Name) + len(pair.Value) + 1)
			builder.WriteString(pair.Name)
			builder.WriteString(separator)
			builder.WriteString(pair.Value)
			flattenedTag = builder.String()
			builder.Reset()
		}

		result = append(result, flattenedTag)
	}

	return result
}

