	return gauge, ok
}

// GetTimer retrieves a timer with the specified name. If it's not found it panics.
func (group *datadogMetricGroup) GetTimer(logContext *log.Context, name string) metrics.Timer {
	timer, ok := group.LookupTimer(name)
	if !ok {
		log.Panicf(logContext, "ERROR: timer '%s' was not found", name)
	}

	return timer
}

// LookupTimer looks up a timer with the given name in the group. If it's not there,
// it returns nil and false; if it's there, it returns the timer and true.
func (group *datadogMetricGroup) LookupTimer(name string) (metrics.Timer, bool) {
	timer, ok := group.timers[name]
	return timer, ok
}
