1. First, create a new metrics group for runtime stats:

```go
// Add these constants
const (
    RuntimeMetricsGroup = "runtime"

    // Runtime metric names
    MetricHeapAlloc        = "heap_alloc"
    MetricHeapSys         = "heap_sys"
    MetricHeapObjects     = "heap_objects"
    MetricGCPauseTotal    = "gc_pause_total"
    MetricGCCount         = "gc_count"
    MetricGoroutines      = "goroutines"
    MetricCPUUsage        = "cpu_usage"
    MetricThreadCount     = "thread_count"
    MetricMemoryUsage     = "memory_usage"
)

// RuntimeMetricsCollector handles collection of runtime metrics
type RuntimeMetricsCollector struct {
    registry metrics.Registry
    group    metrics.Group
    done     chan struct{}
}

func NewRuntimeMetricsCollector(registry metrics.Registry) *RuntimeMetricsCollector {
    group, _ := registry.LookupGroup(RuntimeMetricsGroup)
    return &RuntimeMetricsCollector{
        registry: registry,
        group:    group,
        done:     make(chan struct{}),
    }
}

func (c *RuntimeMetricsCollector) Start(interval time.Duration) {
    ticker := time.NewTicker(interval)
    go func() {
        for {
            select {
            case <-ticker.C:
                c.collect()
            case <-c.done:
                ticker.Stop()
                return
            }
        }
    }()
}

func (c *RuntimeMetricsCollector) Stop() {
    close(c.done)
}

func (c *RuntimeMetricsCollector) collect() {
    var memStats runtime.MemStats
    runtime.ReadMemStats(&memStats)

    // Heap metrics
    if gauge, ok := c.group.LookupGauge(MetricHeapAlloc); ok {
        gauge.Set(float64(memStats.HeapAlloc))
    }

    if gauge, ok := c.group.LookupGauge(MetricHeapSys); ok {
        gauge.Set(float64(memStats.HeapSys))
    }

    if gauge, ok := c.group.LookupGauge(MetricHeapObjects); ok {
        gauge.Set(float64(memStats.HeapObjects))
    }

    // GC metrics
    if gauge, ok := c.group.LookupGauge(MetricGCPauseTotal); ok {
        gauge.Set(float64(memStats.PauseTotalNs))
    }

    if gauge, ok := c.group.LookupGauge(MetricGCCount); ok {
        gauge.Set(float64(memStats.NumGC))
    }

    // Goroutines
    if gauge, ok := c.group.LookupGauge(MetricGoroutines); ok {
        gauge.Set(float64(runtime.NumGoroutine()))
    }

    // Thread count (if available)
    if gauge, ok := c.group.LookupGauge(MetricThreadCount); ok {
        gauge.Set(float64(runtime.NumCPU()))
    }

    // Memory usage
    if gauge, ok := c.group.LookupGauge(MetricMemoryUsage); ok {
        var m runtime.MemStats
        runtime.ReadMemStats(&m)
        gauge.Set(float64(m.Alloc))
    }
}
